INSERT INTO ticket_comments VALUES
    (1,  1,  'customer', 1,  'I purchased the Pro license yesterday but never got a key email.',          '2025-01-06 09:30'),
    (2,  1,  'agent',    2,  'Checking your order now. Can you confirm order #1?',                        '2025-01-06 09:45'),
    (3,  1,  'customer', 1,  'Yes, order #1.',                                                            '2025-01-06 10:00'),
    (4,  1,  'agent',    2,  'Found it — the email bounced. Resending to your updated address now.',      '2025-01-06 13:50'),
    (5,  2,  'customer', 1,  'The W key on my keyboard is stuck glowing red.',                            '2025-02-11 10:15'),
    (6,  2,  'agent',    3,  'Try a firmware reset: hold Fn+Esc for 5 seconds.',                          '2025-02-11 11:00'),
    (7,  2,  'customer', 1,  'That fixed it, thanks!',                                                    '2025-02-12 15:30'),
    (8,  3,  'customer', 2,  'License activation says "key already used".',                               '2025-01-16 08:00'),
    (9,  3,  'agent',    2,  'I''ve reset your activation count. Please try again.',                      '2025-01-16 11:00'),
    (10, 4,  'customer', 2,  'The ear cushion on my headphones is peeling.',                              '2025-03-02 14:00'),
    (11, 4,  'agent',    4,  'Covered under warranty. Sending a replacement pair.',                       '2025-03-02 15:30'),
    (12, 5,  'customer', 3,  'Box arrived crushed. Left driver is rattling.',                             '2025-03-11 09:00'),
    (13, 6,  'customer', 4,  'How many seats does Team include?',                                         '2025-01-21 11:00'),
    (14, 6,  'agent',    2,  'Up to 25 seats. Contact sales for expansion.',                              '2025-01-21 12:30'),
    (15, 8,  'customer', 6,  'Webcam shows as unknown device on Ubuntu 24.04.',                           '2025-03-01 08:45'),
    (16, 8,  'agent',    1,  'What kernel version are you running?',                                      '2025-03-01 09:00'),
    (17, 10, 'customer', 9,  'Mouse registers two clicks per single click.',                              '2025-03-13 11:00'),
    (18, 11, 'customer', 11, 'Pro license gives error on my M3 MacBook.',                                 '2025-01-04 11:00'),
    (19, 11, 'agent',    5,  'Known issue with Rosetta. Updating your license to universal binary.',      '2025-01-04 12:00'),
    (20, 11, 'customer', 11, 'Works now, thanks!',                                                        '2025-01-04 14:30'),
    (21, 12, 'customer', 12, 'Cherry stem snapped when swapping keycaps.',                                '2025-01-11 14:30'),
    (22, 12, 'agent',    6,  'We''ll send replacement stems. Use the included puller tool next time.',    '2025-01-12 09:00'),
    (23, 12, 'customer', 12, 'Got them, all good.',                                                       '2025-01-13 09:00'),
    (24, 13, 'customer', 13, 'Charger pad gets very hot after 30 minutes.',                               '2025-01-13 09:00'),
    (25, 13, 'agent',    5,  'Please stop using it immediately. Sending a replacement with updated firmware.','2025-01-13 10:00'),
    (26, 13, 'customer', 13, 'New one works perfectly, no heat.',                                         '2025-01-13 16:00'),
    (27, 14, 'customer', 14, 'Laptop stand rocks slightly on my desk.',                                   '2025-01-19 10:00'),
    (28, 14, 'agent',    6,  'Try the included rubber pads on the feet.',                                 '2025-01-19 14:00'),
    (29, 14, 'customer', 14, 'Pads fixed it.',                                                            '2025-01-20 11:00'),
    (30, 15, 'customer', 15, 'We have Team and want to upgrade to Enterprise.',                           '2025-01-23 13:00'),
    (31, 15, 'agent',    7,  'I can initiate the upgrade. Your Team balance will be prorated.',            '2025-01-23 15:00'),
    (32, 15, 'customer', 15, 'Sounds good, please proceed.',                                              '2025-01-24 09:00'),
    (33, 15, 'agent',    7,  'Done. Enterprise license activated.',                                       '2025-01-24 10:00'),
    (34, 16, 'customer', 16, 'There''s an echo when I use the mic with Zoom.',                            '2025-01-26 15:00'),
    (35, 16, 'agent',    7,  'Enable "Original Sound" in Zoom settings and disable noise suppression.',   '2025-01-27 09:00'),
    (36, 16, 'customer', 16, 'That cleared it up.',                                                       '2025-01-28 09:00'),
    (37, 17, 'customer', 17, 'Thunderbolt dock shows no video on external monitor.',                      '2025-01-29 08:00'),
    (38, 17, 'agent',    8,  'Which monitor model? Does it work with direct HDMI?',                       '2025-01-29 10:00'),
    (39, 17, 'customer', 17, 'Dell U2723QE. Direct HDMI works fine.',                                     '2025-01-29 14:00'),
    (40, 17, 'agent',    8,  'Try updating dock firmware. I''m sending the utility link.',                 '2025-01-30 09:00'),
    (41, 18, 'customer', 18, 'My cable kit is missing the M4 screws.',                                    '2025-02-02 09:30'),
    (42, 18, 'agent',    5,  'Shipping replacement screws today.',                                        '2025-02-02 10:00'),
    (43, 18, 'customer', 18, 'Got them.',                                                                 '2025-02-02 14:00'),
    (44, 19, 'customer', 19, 'I need to move my Pro license to a new machine.',                           '2025-02-04 10:00'),
    (45, 19, 'agent',    6,  'Deactivated on old machine. You can activate on the new one now.',          '2025-02-04 14:00'),
    (46, 19, 'customer', 19, 'Working on new machine.',                                                   '2025-02-04 16:00'),
    (47, 20, 'customer', 20, 'Left armrest is loose and drops to lowest position.',                       '2025-02-06 11:00'),
    (48, 20, 'agent',    8,  'Tighten the hex bolt under the armrest. If stripped, we''ll send a new arm.','2025-02-06 14:00'),
    (49, 20, 'customer', 20, 'Bolt was loose, tightened and it''s solid now.',                            '2025-02-07 10:00'),
    (50, 21, 'customer', 21, 'Student verification keeps rejecting my .edu email.',                       '2025-02-08 08:00'),
    (51, 21, 'agent',    9,  'What''s the email domain? I can whitelist it.',                              '2025-02-08 09:00'),
    (52, 21, 'customer', 21, 'university.ac.uk',                                                          '2025-02-08 10:00'),
    (53, 21, 'agent',    9,  'Whitelisted. Please retry.',                                                '2025-02-08 11:00'),
    (54, 21, 'customer', 21, 'It went through!',                                                          '2025-02-08 12:00'),
    (55, 22, 'customer', 22, 'Monitor flickers when set to 60Hz over USB-C.',                             '2025-02-09 14:00'),
    (56, 22, 'agent',    10, 'Does it happen at 30Hz? Trying to isolate the issue.',                      '2025-02-09 16:00'),
    (57, 22, 'customer', 22, 'No flicker at 30Hz, only 60.',                                              '2025-02-10 09:00'),
    (58, 22, 'agent',    10, 'Likely a cable bandwidth issue. Sending a certified DP cable to test.',     '2025-02-10 11:00'),
    (59, 23, 'customer', 23, 'PTFE feet on mouse are worn smooth after 2 months.',                        '2025-02-11 09:00'),
    (60, 23, 'agent',    5,  'Normal wear for heavy use. Sending a spare set.',                           '2025-02-11 11:00'),
    (61, 23, 'customer', 23, 'Replacement feet feel great.',                                              '2025-02-12 11:00'),
    (62, 24, 'customer', 24, 'Bluetooth audio cuts out every 30 seconds.',                                '2025-02-13 10:30'),
    (63, 24, 'agent',    6,  'Reset the Bluetooth module: hold power + volume down 10 seconds.',          '2025-02-13 12:00'),
    (64, 24, 'customer', 24, 'Reset fixed it, solid connection now.',                                     '2025-02-14 15:00'),
    (65, 25, 'customer', 25, 'Hub not delivering power to my laptop while charging phone.',               '2025-02-15 08:00'),
    (66, 25, 'agent',    7,  'The hub provides 60W max. Your laptop needs 65W. Use the laptop charger separately.','2025-02-15 10:00'),
    (67, 25, 'customer', 25, 'Understood. Would a powered hub solve this?',                               '2025-02-15 14:00'),
    (68, 25, 'agent',    7,  'Yes, or our Thunderbolt dock which provides 96W.',                          '2025-02-15 17:00'),
    (69, 26, 'customer', 26, 'Desk lamp flickers at the lowest brightness setting.',                      '2025-02-17 11:00'),
    (70, 26, 'agent',    10, 'Known issue on early batch. Firmware update fixes it.',                     '2025-02-17 14:00'),
    (71, 26, 'customer', 26, 'Updated, no more flicker.',                                                '2025-02-18 09:00'),
    (72, 27, 'customer', 27, 'Keyboard completely unresponsive after firmware update!',                   '2025-02-19 07:30'),
    (73, 27, 'agent',    6,  'Hold Esc while plugging in to enter recovery mode. Re-flash with v2.1.',   '2025-02-19 08:00'),
    (74, 27, 'customer', 27, 'Recovery mode worked. All good now.',                                       '2025-02-19 12:00'),
    (75, 28, 'customer', 28, 'Numpad works on Windows but not macOS.',                                    '2025-02-21 10:00'),
    (76, 28, 'agent',    7,  'Switch to Mac mode with Fn+M. The default is Windows mode.',                '2025-02-21 12:00'),
    (77, 28, 'customer', 28, 'That did it.',                                                              '2025-02-22 09:00'),
    (78, 29, 'customer', 29, 'Desk mat edge is curling up on the left side.',                             '2025-02-23 14:00'),
    (79, 29, 'agent',    9,  'Place heavy books on the edge overnight to flatten it.',                    '2025-02-23 16:00'),
    (80, 29, 'customer', 29, 'Flat now.',                                                                 '2025-02-24 10:00'),
    (81, 30, 'customer', 30, 'Monitor arm slowly sinks throughout the day.',                              '2025-02-25 09:00'),
    (82, 30, 'agent',    10, 'Increase the tension via the hex key on the joint.',                        '2025-02-25 11:00'),
    (83, 30, 'customer', 30, 'Tightened, holds position now.',                                            '2025-02-26 11:00'),
    (84, 31, 'customer', 31, 'We need SSO with Okta for our Enterprise account.',                         '2025-02-27 08:00'),
    (85, 31, 'agent',    4,  'I''ll set up a call with our integrations team.',                           '2025-02-27 10:00'),
    (86, 31, 'customer', 31, 'Call went well, config is live.',                                           '2025-02-28 17:00'),
    (87, 32, 'customer', 33, 'Plugin SDK docs are missing the event hook section.',                       '2025-03-02 10:00'),
    (88, 32, 'agent',    8,  'You''re right, that section is still WIP. Adding it this week.',            '2025-03-02 14:00'),
    (89, 33, 'customer', 34, 'Privacy screen has air bubbles forming.',                                  '2025-03-03 11:00'),
    (90, 33, 'agent',    5,  'Remove and reapply using the included squeegee. Start from center out.',   '2025-03-03 14:00'),
    (91, 33, 'customer', 34, 'Reapplied, looks clean now.',                                              '2025-03-04 09:00'),
    (92, 34, 'customer', 35, 'Webcam hunts for focus in dim lighting.',                                  '2025-03-04 14:00'),
    (93, 34, 'agent',    6,  'Lock focus via our companion app. Set to manual and adjust.',              '2025-03-04 16:00'),
    (94, 34, 'customer', 35, 'Manual focus works great.',                                                '2025-03-05 10:00'),
    (95, 35, 'customer', 36, 'Stitching on mousepad is coming undone at the front edge.',                '2025-03-05 09:00'),
    (96, 35, 'agent',    7,  'Sending a replacement. This batch had a stitching defect.',                '2025-03-05 11:00'),
    (97, 35, 'customer', 36, 'New pad received, stitching is solid.',                                    '2025-03-05 15:00'),
    (98, 36, 'customer', 37, 'Cable connection drops when I wiggle the connector.',                      '2025-03-06 10:00'),
    (99, 36, 'agent',    10, 'Sounds like a defective cable. Sending a replacement set.',                '2025-03-06 12:00'),
    (100,36, 'customer', 37, 'New cables work perfectly.',                                               '2025-03-07 09:00'),
    (101,37, 'customer', 38, 'Webcam covers are too wide for my ultrawide bezel.',                       '2025-03-07 11:00'),
    (102,37, 'agent',    9,  'We have slim covers for ultrawide. Sending a pack.',                       '2025-03-07 12:00'),
    (103,37, 'customer', 38, 'Slim covers fit perfectly.',                                               '2025-03-07 14:00'),
    (104,38, 'customer', 39, 'Standing desk motor makes grinding noise going up.',                       '2025-03-08 08:00'),
    (105,38, 'agent',    6,  'Please stop using it and send a video. Could be a motor issue.',           '2025-03-08 09:00'),
    (106,39, 'customer', 40, 'Rain sound on noise machine crackles at high volume.',                     '2025-03-09 10:00'),
    (107,39, 'agent',    7,  'Reset to factory defaults: hold both buttons 5 seconds.',                  '2025-03-09 12:00'),
    (108,39, 'customer', 40, 'Factory reset fixed the crackling.',                                       '2025-03-10 09:00'),
    (109,40, 'customer', 41, 'License shows expired but I have annual billing.',                         '2025-03-10 08:00'),
    (110,40, 'agent',    10, 'Checking your account. Looks like a billing sync delay.',                  '2025-03-10 10:00'),
    (111,42, 'customer', 43, 'Spacebar has a metallic rattle on press.',                                 '2025-03-12 10:00'),
    (112,42, 'agent',    5,  'Apply a small piece of tape on the stabilizer wire. I''ll send a video guide.','2025-03-12 12:00'),
    (113,42, 'customer', 43, 'Tape mod worked, no more rattle.',                                         '2025-03-13 09:00'),
    (114,43, 'customer', 44, 'Hub drops devices when I plug in a 4th device.',                           '2025-03-13 11:00'),
    (115,43, 'agent',    6,  'Try without the external drive. Some drives draw too much power.',         '2025-03-13 14:00'),
    (116,43, 'customer', 44, 'Removing the drive fixed it. I''ll use a powered enclosure.',              '2025-03-14 10:00'),
    (117,46, 'customer', 47, 'Drawer on desk organiser is jammed shut.',                                 '2025-03-16 10:00'),
    (118,46, 'agent',    10, 'Press the release tab on the underside while pulling.',                    '2025-03-16 11:00'),
    (119,46, 'customer', 47, 'Found the tab, drawer opens now.',                                         '2025-03-16 15:00'),
    (120,50, 'customer', 1,  'Desk won''t go below 28 inches. Should go to 25.',                         '2025-03-20 08:00');
INSERT INTO kb_articles VALUES
    (1,  'How to activate your LatticeQL license',     'Step 1: Open Settings > License. Step 2: Paste your key. Step 3: Click Activate.', 1, 2, 1, '2025-01-10', '2025-01-16'),
    (2,  'Keyboard firmware reset guide',               'Hold Fn+Esc for 5 seconds to perform a full firmware reset.',                      2, 3, 1, '2025-02-12', '2025-02-12'),
    (3,  'Webcam Linux compatibility',                  'The 4K webcam requires kernel 5.15+ and the uvcvideo module.',                     9, 4, 1, '2025-03-02', '2025-03-02'),
    (4,  'Headphone warranty and replacements',         'All headphones include a 2-year warranty covering manufacturing defects.',          5, 4, 1, '2025-02-01', '2025-03-02'),
    (5,  'Team license FAQ',                            'The Team license covers up to 25 seats. Volume discounts for 50+.',                6, 2, 1, '2025-01-22', '2025-01-22'),
    (6,  'Mouse double-click troubleshooting',          'Try updating firmware. If issue persists, request warranty replacement.',           7, 3, 0, '2025-03-14', '2025-03-14'),
    (7,  'Thunderbolt dock setup guide',                'Connect dock to laptop via Thunderbolt cable. Install companion app for firmware.', 19,8, 1, '2025-01-30', '2025-02-15'),
    (8,  'License transfer between machines',           'Deactivate via Settings > License > Deactivate, then activate on new machine.',    1, 6, 1, '2025-02-05', '2025-02-05'),
    (9,  'Office chair adjustment guide',               'Adjust seat height, lumbar, armrests, and tilt tension for ergonomic posture.',     22,8, 1, '2025-02-07', '2025-02-07'),
    (10, 'Student license eligibility',                 'Available for students with a valid .edu or equivalent academic email.',            21,9, 1, '2025-02-08', '2025-02-08'),
    (11, 'Wireless charger safety notice',              'If the charger becomes hot, stop use immediately and contact support.',             12,5, 1, '2025-01-14', '2025-01-14'),
    (12, 'Enterprise SSO integration',                  'Supported providers: Okta, Azure AD, OneLogin. Contact support to configure.',      11,4, 1, '2025-02-28', '2025-02-28'),
    (13, 'Keyboard recovery mode',                      'Hold Esc while plugging in USB to enter recovery. Re-flash with latest firmware.',  2, 6, 1, '2025-02-19', '2025-02-19'),
    (14, 'USB-C hub power delivery explained',          'Hub provides 60W passthrough. Laptops requiring 65W+ need a separate charger.',    3, 7, 1, '2025-02-16', '2025-02-16'),
    (15, 'Portable monitor troubleshooting',            'Use a certified DP Alt Mode cable. Some USB-C cables lack video support.',          23,10,1, '2025-02-10', '2025-02-10'),
    (16, 'Standing desk maintenance',                   'Lubricate lift columns annually. Do not exceed weight limit of 150 lbs.',           29,7, 1, '2025-03-08', '2025-03-08'),
    (17, 'Desk lamp firmware update',                   'Download updater from support portal. Connect lamp via USB-C during update.',       17,10,1, '2025-02-18', '2025-02-18'),
    (18, 'Mouse feet replacement guide',                'Peel old feet with included tool. Clean surface, then press new feet firmly.',      7, 5, 1, '2025-02-12', '2025-02-12'),
    (19, 'Plugin SDK getting started',                  'Install the SDK via cargo. See examples/ directory for event hook patterns.',       28,8, 0, '2025-03-02', '2025-03-02'),
    (20, 'Webcam companion app manual focus',           'Open app, select camera, switch to Manual focus tab. Adjust slider.',               9, 6, 1, '2025-03-05', '2025-03-05');
